import React from 'react';
import { Pressable, StyleSheet, Text, View, ViewStyle } from 'react-native';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';
import { haptic } from '../utils/haptics';

type Props = {
  label: string;
  icon?: string;
  onPress: () => void;
  variant?: 'primary' | 'success' | 'danger' | 'muted';
  style?: ViewStyle;
  disabled?: boolean;
};

const variantBg: Record<NonNullable<Props['variant']>, string> = {
  primary: colors.primary,
  success: colors.success,
  danger: colors.danger,
  muted: colors.bgMuted,
};

export function BigButton({ label, icon, onPress, variant = 'primary', style, disabled }: Props) {
  const isMuted = variant === 'muted';
  return (
    <Pressable
      onPress={() => {
        haptic.tap();
        onPress();
      }}
      disabled={disabled}
      style={({ pressed }) => [
        styles.btn,
        { backgroundColor: variantBg[variant], opacity: disabled ? 0.5 : pressed ? 0.85 : 1 },
        style,
      ]}
    >
      <View style={styles.row}>
        {icon ? <Text style={[styles.icon, isMuted && { color: colors.text }]}>{icon}</Text> : null}
        <Text style={[styles.label, isMuted && { color: colors.text }]}>{label}</Text>
      </View>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  btn: {
    minHeight: 72,
    borderRadius: radius.lg,
    paddingHorizontal: spacing.lg,
    paddingVertical: spacing.md,
    justifyContent: 'center',
  },
  row: { flexDirection: 'row', alignItems: 'center', justifyContent: 'center' },
  icon: { fontSize: fontSize.xl, color: '#fff', marginRight: spacing.md },
  label: { fontSize: fontSize.lg, color: '#fff', fontWeight: '700' },
});

