import { CameraView, useCameraPermissions } from 'expo-camera';
import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { BigButton } from '../components/BigButton';
import { findProduct } from '../db/products';
import { RootStackParamList } from '../navigation/types';
import { colors } from '../theme/colors';
import { fontSize, spacing } from '../theme/spacing';
import { haptic } from '../utils/haptics';

type Props = NativeStackScreenProps<RootStackParamList, 'Scanner'>;

const SUPPORTED = ['ean13', 'ean8', 'upc_a', 'upc_e', 'code128', 'code39', 'qr'] as const;

export function ScannerScreen({ navigation }: Props) {
  const [permission, requestPermission] = useCameraPermissions();
  const [lastCode, setLastCode] = useState<string | null>(null);
  const lockedRef = useRef(false);

  useEffect(() => {
    if (permission && !permission.granted && permission.canAskAgain) requestPermission();
  }, [permission, requestPermission]);

  const handleScan = useCallback(
    async ({ data }: { data: string }) => {
      if (lockedRef.current || !data) return;
      lockedRef.current = true;
      setLastCode(data);
      haptic.success();
      const existing = await findProduct(data).catch(() => null);
      if (existing) navigation.replace('Receiving', { barcode: data });
      else navigation.replace('RegisterProduct', { barcode: data });
    },
    [navigation]
  );

  if (!permission) {
    return (
      <SafeAreaView style={styles.center}>
        <Text style={styles.info}>Loading camera…</Text>
      </SafeAreaView>
    );
  }

  if (!permission.granted) {
    return (
      <SafeAreaView style={styles.center}>
        <Text style={styles.info}>Camera permission is required to scan items.</Text>
        <BigButton label="Allow camera" icon="📷" onPress={requestPermission} />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.cameraWrap}>
        <CameraView
          style={StyleSheet.absoluteFill}
          facing="back"
          barcodeScannerSettings={{ barcodeTypes: [...SUPPORTED] }}
          onBarcodeScanned={handleScan}
        />
        <View style={styles.frame} pointerEvents="none" />
      </View>

      <View style={styles.footer}>
        <Text style={styles.hint}>{lastCode ? `Scanned: ${lastCode}` : 'Point camera at barcode'}</Text>
        <BigButton label="Cancel" variant="muted" onPress={() => navigation.goBack()} />
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: colors.text },
  center: { flex: 1, backgroundColor: colors.bg, padding: spacing.lg, justifyContent: 'center', gap: spacing.md },
  info: { fontSize: fontSize.md, color: colors.text, textAlign: 'center', marginBottom: spacing.md },
  cameraWrap: { flex: 1, overflow: 'hidden' },
  frame: {
    position: 'absolute',
    top: '25%',
    left: '10%',
    right: '10%',
    bottom: '35%',
    borderWidth: 3,
    borderColor: '#fff',
    borderRadius: 16,
  },
  footer: { padding: spacing.lg, backgroundColor: colors.text, gap: spacing.md },
  hint: { color: '#fff', fontSize: fontSize.md, textAlign: 'center' },
});

