import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useState } from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native';
import { BigButton } from '../components/BigButton';
import { enqueue } from '../db/outbox';
import { upsertProduct } from '../db/products';
import { RootStackParamList } from '../navigation/types';
import { flushOnce } from '../sync/syncService';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';
import { haptic } from '../utils/haptics';

type Props = NativeStackScreenProps<RootStackParamList, 'RegisterProduct'>;

const CATEGORIES = ['Grocery', 'Cleaning', 'Office', 'Cafeteria', 'Other'];
const UNITS = ['Piece', 'Kg', 'Litre', 'Pack', 'Box'];

export function RegisterProductScreen({ route, navigation }: Props) {
  const { barcode } = route.params;
  const [name, setName] = useState('');
  const [category, setCategory] = useState<string>('Grocery');
  const [unit, setUnit] = useState<string>('Piece');
  const [saving, setSaving] = useState(false);

  const onSave = async () => {
    if (!name.trim()) {
      haptic.warn();
      return;
    }
    setSaving(true);
    try {
      await upsertProduct({ barcode, name: name.trim(), category, unit });
      await enqueue('product_registration', { barcode, name: name.trim(), category, unit });
      flushOnce().catch(() => {});
      haptic.success();
      navigation.replace('Receiving', { barcode });
    } finally {
      setSaving(false);
    }
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <Text style={styles.h1}>New product</Text>
        <Text style={styles.meta}>Barcode: {barcode}</Text>

        <Text style={styles.label}>Name</Text>
        <TextInput
          value={name}
          onChangeText={setName}
          placeholder="e.g. Tata Salt 1kg"
          style={styles.input}
          autoFocus
        />

        <Text style={styles.label}>Category</Text>
        <View style={styles.chipRow}>
          {CATEGORIES.map((c) => (
            <Chip key={c} label={c} active={c === category} onPress={() => setCategory(c)} />
          ))}
        </View>

        <Text style={styles.label}>Unit</Text>
        <View style={styles.chipRow}>
          {UNITS.map((u) => (
            <Chip key={u} label={u} active={u === unit} onPress={() => setUnit(u)} />
          ))}
        </View>

        <View style={{ height: spacing.lg }} />
        <BigButton
          label={saving ? 'Saving…' : 'Save & continue'}
          icon="✓"
          variant="success"
          onPress={onSave}
          disabled={saving || !name.trim()}
        />
        <BigButton label="Cancel" variant="muted" onPress={() => navigation.popToTop()} />
      </ScrollView>
    </SafeAreaView>
  );
}

function Chip({ label, active, onPress }: { label: string; active: boolean; onPress: () => void }) {
  return (
    <Pressable
      onPress={() => {
        haptic.tap();
        onPress();
      }}
      style={[styles.chip, active && styles.chipActive]}
    >
      <Text style={[styles.chipText, active && styles.chipTextActive]}>{label}</Text>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: colors.bg },
  scroll: { padding: spacing.lg, gap: spacing.sm },
  h1: { fontSize: fontSize.xl, fontWeight: '800', color: colors.text },
  meta: { fontSize: fontSize.md, color: colors.textMuted, marginBottom: spacing.md },
  label: { fontSize: fontSize.md, fontWeight: '700', color: colors.text, marginTop: spacing.md },
  input: {
    borderWidth: 2,
    borderColor: colors.border,
    borderRadius: radius.md,
    padding: spacing.md,
    fontSize: fontSize.lg,
    backgroundColor: '#fff',
  },
  chipRow: { flexDirection: 'row', flexWrap: 'wrap', gap: spacing.sm },
  chip: {
    paddingVertical: spacing.sm,
    paddingHorizontal: spacing.md,
    borderRadius: radius.lg,
    borderWidth: 2,
    borderColor: colors.border,
    backgroundColor: '#fff',
  },
  chipActive: { backgroundColor: colors.primary, borderColor: colors.primary },
  chipText: { fontSize: fontSize.md, color: colors.text, fontWeight: '600' },
  chipTextActive: { color: '#fff' },
});

