import { NativeStackScreenProps } from '@react-navigation/native-stack';
import { nanoid } from 'nanoid/non-secure';
import React, { useEffect, useState } from 'react';
import { Pressable, SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { BigButton } from '../components/BigButton';
import { addReceivedQty, findOpenItemByBarcode, OrderItem } from '../db/orders';
import { enqueue } from '../db/outbox';
import { findProduct, Product } from '../db/products';
import { RootStackParamList } from '../navigation/types';
import { flushOnce } from '../sync/syncService';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';
import { haptic } from '../utils/haptics';

type Props = NativeStackScreenProps<RootStackParamList, 'Receiving'>;

export function ReceivingScreen({ route, navigation }: Props) {
  const { barcode } = route.params;
  const [product, setProduct] = useState<Product | null>(null);
  const [item, setItem] = useState<OrderItem | null>(null);
  const [qty, setQty] = useState(1);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    (async () => {
      setProduct(await findProduct(barcode));
      setItem(await findOpenItemByBarcode(barcode));
    })();
  }, [barcode]);

  const bump = (n: number) => {
    haptic.tap();
    setQty((q) => Math.max(1, q + n));
  };

  const confirm = async () => {
    setSaving(true);
    try {
      const id = `rcp_${nanoid(12)}`;
      const payload = {
        id,
        order_id: item?.order_id ?? null,
        order_item_id: item?.id ?? null,
        barcode,
        product_name: product?.name ?? 'Unknown',
        qty,
        scanned_at: Date.now(),
      };
      await enqueue('receipt', payload);
      if (item) await addReceivedQty(item.id, qty);
      flushOnce().catch(() => {});
      haptic.success();
      navigation.replace('Scanner');
    } finally {
      setSaving(false);
    }
  };

  const expected = item?.expected_qty ?? null;
  const alreadyIn = item?.received_qty ?? 0;
  const mismatch = expected !== null && alreadyIn + qty > expected;

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.card}>
        <Text style={styles.name}>{product?.name ?? 'Unknown product'}</Text>
        <Text style={styles.meta}>Barcode: {barcode}</Text>
        {expected !== null && (
          <Text style={[styles.expected, mismatch && { color: colors.danger }]}>
            Expected {expected} · received {alreadyIn} so far
          </Text>
        )}
      </View>

      <View style={styles.qtyRow}>
        <Pressable style={styles.qtyBtn} onPress={() => bump(-1)}>
          <Text style={styles.qtyBtnText}>−</Text>
        </Pressable>
        <Text style={styles.qtyNum}>{qty}</Text>
        <Pressable style={styles.qtyBtn} onPress={() => bump(1)}>
          <Text style={styles.qtyBtnText}>+</Text>
        </Pressable>
      </View>

      <View style={styles.quickRow}>
        {[5, 10, 20].map((n) => (
          <Pressable key={n} style={styles.quickBtn} onPress={() => { haptic.tap(); setQty(n); }}>
            <Text style={styles.quickText}>{n}</Text>
          </Pressable>
        ))}
      </View>

      {mismatch && <Text style={styles.warn}>⚠ More than expected</Text>}

      <View style={styles.footer}>
        <BigButton
          label={saving ? 'Saving…' : 'Confirm received'}
          icon="✓"
          variant="success"
          onPress={confirm}
          disabled={saving}
        />
        <BigButton label="Cancel" variant="muted" onPress={() => navigation.popToTop()} />
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: colors.bg, padding: spacing.lg, gap: spacing.lg },
  card: {
    padding: spacing.lg,
    backgroundColor: colors.bgMuted,
    borderRadius: radius.lg,
  },
  name: { fontSize: fontSize.xl, fontWeight: '800', color: colors.text },
  meta: { fontSize: fontSize.sm, color: colors.textMuted, marginTop: spacing.xs },
  expected: { marginTop: spacing.md, fontSize: fontSize.md, color: colors.text, fontWeight: '600' },
  qtyRow: { flexDirection: 'row', alignItems: 'center', justifyContent: 'center', gap: spacing.lg },
  qtyBtn: {
    width: 88,
    height: 88,
    borderRadius: 44,
    backgroundColor: colors.primary,
    alignItems: 'center',
    justifyContent: 'center',
  },
  qtyBtnText: { color: '#fff', fontSize: 48, fontWeight: '800', lineHeight: 52 },
  qtyNum: { fontSize: 72, fontWeight: '900', color: colors.text, minWidth: 120, textAlign: 'center' },
  quickRow: { flexDirection: 'row', justifyContent: 'center', gap: spacing.md },
  quickBtn: {
    paddingVertical: spacing.sm,
    paddingHorizontal: spacing.lg,
    borderRadius: radius.lg,
    borderWidth: 2,
    borderColor: colors.border,
  },
  quickText: { fontSize: fontSize.lg, fontWeight: '700', color: colors.text },
  warn: { color: colors.danger, fontSize: fontSize.md, fontWeight: '700', textAlign: 'center' },
  footer: { gap: spacing.md, marginTop: 'auto' },
});

