import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useState } from 'react';
import { FlatList, SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { BigButton } from '../components/BigButton';
import { getDb } from '../db/database';
import { getOrderItems, listOpenOrders, Order, OrderItem } from '../db/orders';
import { RootStackParamList } from '../navigation/types';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';

type Props = NativeStackScreenProps<RootStackParamList, 'Orders'>;

type OrderWithItems = Order & { items: OrderItem[] };

export function OrdersScreen({ navigation }: Props) {
  const [orders, setOrders] = useState<OrderWithItems[]>([]);

  const load = useCallback(async () => {
    await getDb();
    const list = await listOpenOrders();
    const enriched = await Promise.all(
      list.map(async (o) => ({ ...o, items: await getOrderItems(o.id) }))
    );
    setOrders(enriched);
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  return (
    <SafeAreaView style={styles.safe}>
      <Text style={styles.h1}>Expected deliveries</Text>
      <FlatList
        data={orders}
        keyExtractor={(o) => o.id}
        renderItem={({ item }) => (
          <View style={styles.card}>
            <Text style={styles.vendor}>{item.vendor ?? 'Order'}</Text>
            {item.expected_at && (
              <Text style={styles.meta}>Due: {new Date(item.expected_at).toLocaleDateString()}</Text>
            )}
            <View style={{ height: spacing.sm }} />
            {item.items.map((i) => {
              const done = i.received_qty >= i.expected_qty;
              return (
                <View key={i.id} style={styles.itemRow}>
                  <Text style={[styles.itemName, done && { color: colors.success }]}>
                    {done ? '✓ ' : ''}{i.product_name}
                  </Text>
                  <Text style={styles.itemQty}>
                    {i.received_qty} / {i.expected_qty}
                  </Text>
                </View>
              );
            })}
          </View>
        )}
        ListEmptyComponent={
          <Text style={styles.empty}>
            No expected deliveries. Orders sync from the server when bills are processed.
          </Text>
        }
        contentContainerStyle={{ gap: spacing.md, paddingBottom: spacing.lg }}
      />
      <BigButton label="Back" variant="muted" onPress={() => navigation.goBack()} />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: colors.bg, padding: spacing.lg, gap: spacing.md },
  h1: { fontSize: fontSize.xl, fontWeight: '800', color: colors.text },
  card: { padding: spacing.md, backgroundColor: colors.bgMuted, borderRadius: radius.md },
  vendor: { fontSize: fontSize.lg, fontWeight: '700', color: colors.text },
  meta: { fontSize: fontSize.sm, color: colors.textMuted, marginTop: 2 },
  itemRow: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: spacing.xs },
  itemName: { fontSize: fontSize.md, color: colors.text, flex: 1 },
  itemQty: { fontSize: fontSize.md, color: colors.text, fontWeight: '700' },
  empty: { textAlign: 'center', color: colors.textMuted, marginTop: spacing.xl, fontSize: fontSize.md, paddingHorizontal: spacing.lg },
});

