  surfaceContainerHigh: '#E5E9E2',
  surfaceContainerHighest: '#DFE3DC',

  onSurfaceVariant: '#414941',
  outline: '#717971',
  outlineVariant: '#C1C9BF',

  scrim: 'rgba(0,0,0,0.45)',
} as const;

