};

export function Surface({
  tone = 'lowest',
  level = 'level0',
  rounded = 'lg',
  style,
  children,
  ...rest
}: Props) {
  return (
    <View
      {...rest}
      style={[
        { backgroundColor: toneToColor[tone], borderRadius: radius[rounded] },
        elev[level],
        style,
      ]}
    >
      {children}
    </View>
  );
}

