import React, { useEffect, useState } from 'react';
import { StyleSheet, Text, View } from 'react-native';
import { onPendingChange } from '../sync/syncService';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';

export function QueueBadge() {
  const [count, setCount] = useState(0);
  useEffect(() => onPendingChange(setCount), []);
  const ok = count === 0;
  return (
    <View style={[styles.box, { backgroundColor: ok ? colors.success : colors.warn }]}>
      <Text style={styles.text}>{ok ? '✓ All synced' : `${count} waiting to send`}</Text>
