  );
}

const styles = StyleSheet.create({
  box: {
    paddingVertical: spacing.sm,
    paddingHorizontal: spacing.md,
    borderRadius: radius.md,
    alignSelf: 'flex-start',
  },
  text: { color: '#fff', fontWeight: '700', fontSize: fontSize.md },
});

