import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useState } from 'react';
import { FlatList, RefreshControl, SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { BigButton } from '../components/BigButton';
import { getDb } from '../db/database';
import { OutboxRow } from '../db/outbox';
import { RootStackParamList } from '../navigation/types';
import { flushOnce } from '../sync/syncService';
import { colors } from '../theme/colors';
import { fontSize, radius, spacing } from '../theme/spacing';

type Props = NativeStackScreenProps<RootStackParamList, 'Outbox'>;

export function OutboxScreen({ navigation }: Props) {
  const [rows, setRows] = useState<OutboxRow[]>([]);
  const [busy, setBusy] = useState(false);

  const load = useCallback(async () => {
    const db = await getDb();
    const list = await db.getAllAsync<OutboxRow>(
      'SELECT * FROM outbox ORDER BY created_at DESC LIMIT 100'
    );
    setRows(list);
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const sync = async () => {
    setBusy(true);
    try {
      await flushOnce();
      await load();
    } finally {
      setBusy(false);
    }
  };

  return (
    <SafeAreaView style={styles.safe}>
      <Text style={styles.h1}>Sync queue</Text>
      <FlatList
        data={rows}
        keyExtractor={(r) => r.id}
        refreshControl={<RefreshControl refreshing={busy} onRefresh={sync} />}
        renderItem={({ item }) => (
          <View style={styles.row}>
            <View style={{ flex: 1 }}>
              <Text style={styles.rowTitle}>{item.kind}</Text>
              <Text style={styles.rowMeta}>
                {new Date(item.created_at).toLocaleString()} · attempts {item.attempts}
              </Text>
              {item.last_error && <Text style={styles.err}>{item.last_error}</Text>}
            </View>
            <View style={[styles.badge, badgeStyle(item.status)]}>
              <Text style={styles.badgeText}>{item.status}</Text>
            </View>
          </View>
        )}
        ListEmptyComponent={<Text style={styles.empty}>Nothing in the queue.</Text>}
        contentContainerStyle={{ gap: spacing.sm, paddingBottom: spacing.lg }}
      />
      <BigButton label={busy ? 'Syncing…' : 'Sync now'} icon="🔄" onPress={sync} disabled={busy} />
      <BigButton label="Back" variant="muted" onPress={() => navigation.goBack()} />
