import { CameraView, useCameraPermissions } from 'expo-camera';
import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  Animated,
  Easing,
  Platform,
  Pressable,
  StyleSheet,
  View,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Button, IconButton, palette, spacing, Text } from '../design';
import { findProduct } from '../db/products';
import { RootStackParamList } from '../navigation/types';
import { haptic } from '../utils/haptics';

type Props = NativeStackScreenProps<RootStackParamList, 'Scanner'>;

// All formats expo-camera supports. Worn / damaged / off-standard labels in
// the field can be any of these, so we accept them all and let the decoder
// pick. Trimming this list breaks real scans.
const FORMATS = [
  'aztec',
  'codabar',
  'code39',
  'code93',
  'code128',
  'datamatrix',
  'ean8',
  'ean13',
  'itf14',
  'pdf417',
  'qr',
  'upc_a',
  'upc_e',
] as const;

export function ScannerScreen({ navigation }: Props) {
  const [permission, requestPermission] = useCameraPermissions();
  const [torch, setTorch] = useState(false);
  const lockedRef = useRef(false);
  const flashOpacity = useRef(new Animated.Value(0)).current;
  const linePos = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (permission && !permission.granted && permission.canAskAgain) requestPermission();
  }, [permission, requestPermission]);

  useEffect(() => {
    const anim = Animated.loop(
      Animated.sequence([
        Animated.timing(linePos, { toValue: 1, duration: 1600, easing: Easing.inOut(Easing.ease), useNativeDriver: true }),
        Animated.timing(linePos, { toValue: 0, duration: 1600, easing: Easing.inOut(Easing.ease), useNativeDriver: true }),
      ])
    );
    anim.start();
    return () => anim.stop();
  }, [linePos]);

  const flash = useCallback(() => {
    flashOpacity.setValue(0.6);
    Animated.timing(flashOpacity, { toValue: 0, duration: 240, useNativeDriver: true }).start();
  }, [flashOpacity]);

  const handleScan = useCallback(
    ({ data, type }: { data: string; type?: string }) => {
      // Always log — useful for diagnosing format coverage (GS1-128, DataBar,
      // SSCC, etc.). Strip FNC1 (ASCII 29) so the printable payload is visible.
      const printable = data?.replace(/\x1d/g, '|');
      console.log('[scan]', type, JSON.stringify(printable));
      if (lockedRef.current || !data) return;
      lockedRef.current = true;
      haptic.success();
      flash();
      // Fire-and-forget DB lookup, navigate as soon as we know the answer.
      // Synchronous lock above already prevents duplicate scans.
      findProduct(data)
        .then((existing) => {
          if (existing) navigation.replace('Receiving', { barcode: data });
          else navigation.replace('RegisterProduct', { barcode: data });
        })
        .catch(() => {
          // If lookup fails, fall back to registration to be safe.
          navigation.replace('RegisterProduct', { barcode: data });
        });
    },
    [navigation, flash]
  );

  const barcodeSettings = useMemo(
    () => ({ barcodeTypes: [...FORMATS] }),
    []
  );

  const lineY = linePos.interpolate({ inputRange: [0, 1], outputRange: [0, 220] });

  if (!permission) {
    return <View style={styles.center} />;
  }

  if (!permission.granted) {
    return (
      <SafeAreaView style={styles.permission}>
        <Text variant="headlineSmall" style={{ textAlign: 'center', marginBottom: spacing.md }}>
          Camera access needed
        </Text>
        <Text
          variant="bodyLarge"
          color={palette.onSurfaceVariant}
          style={{ textAlign: 'center', marginBottom: spacing.xl }}
        >
          We use the camera only to read barcodes — no photos are taken.
        </Text>
        <Button label="Allow camera" onPress={requestPermission} size="lg" fullWidth />
        <Button
          label="Not now"
          variant="text"
          onPress={() => navigation.goBack()}
          style={{ marginTop: spacing.sm }}
        />
      </SafeAreaView>
    );
  }

  return (
    <View style={styles.root}>
      <CameraView
        style={StyleSheet.absoluteFill}
        facing="back"
        enableTorch={torch}
        barcodeScannerSettings={barcodeSettings}
        onBarcodeScanned={handleScan}
        // @ts-ignore — Android-only prop, ignored elsewhere
        autofocus="on"
      />

      {/* Dim mask with a transparent window */}
      <View style={styles.maskTop} />
      <View style={styles.maskRow}>
        <View style={styles.maskSide} />
        <View style={styles.window}>
          <View style={[styles.corner, styles.cornerTL]} />
          <View style={[styles.corner, styles.cornerTR]} />
          <View style={[styles.corner, styles.cornerBL]} />
          <View style={[styles.corner, styles.cornerBR]} />
          <Animated.View style={[styles.scanLine, { transform: [{ translateY: lineY }] }]} />
        </View>
        <View style={styles.maskSide} />
      </View>
      <View style={styles.maskBottom} />

      <Animated.View pointerEvents="none" style={[styles.flash, { opacity: flashOpacity }]} />

      <SafeAreaView edges={['top']} style={styles.topBar}>
        <View style={styles.topBarRow}>
          <IconButton icon="✕" onPress={() => navigation.goBack()} tone="inverse" />
          <Text variant="titleMedium" color="#fff">
            Scan barcode
          </Text>
          <IconButton
            icon={torch ? '◉' : '○'}
            onPress={() => setTorch((t) => !t)}
            tone="inverse"
          />
        </View>
      </SafeAreaView>

      <SafeAreaView edges={['bottom']} style={styles.hint}>
        <Text
          variant="bodyLarge"
          color="#fff"
          style={{ textAlign: 'center', paddingHorizontal: spacing.xl }}
        >
          Hold steady. Align the barcode inside the frame.
        </Text>
      </SafeAreaView>
    </View>
  );
}

